import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode; // Import OWASP Encoder for HTML encoding
import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

@WebServlet("/xss-secure")
public class XSSSecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Encode user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        // Set content type and get PrintWriter
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        // Write HTML response with encoded user input
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Hello " + encodedUserInput + "</h1>"); // Safe from XSS
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
